const FIRST_TXN_CONFIRM_MODE = 'first_txn_confirm';
const FIRST_TXN_COMMIT_TTL_MS = Number(process.env.FIRST_TXN_COMMIT_TTL_MS ?? 120_000);
globalThis._firstTxnCommitGrace = globalThis._firstTxnCommitGrace ?? new Map(); // shopId -> ts
function _firstTxnCommitAllowed(shopId) {
  try {
    const key = String(shopId ?? '');
    const now = Date.now();
    const prev = globalThis._firstTxnCommitGrace.get(key);
    if (prev && (now - prev) < FIRST_TXN_COMMIT_TTL_MS) return false;
    globalThis._firstTxnCommitGrace.set(key, now);
    return true;
  } catch { return true; }
}
function _isYes(text='') {
  const t = String(text ?? '').trim().toLowerCase();
  return /^(haan|han|ha|haanji|yes|y|ok|okay|sahi|thik|theek)/.test(t);
}
function _isNo(text='') {
  const t = String(text ?? '').trim().toLowerCase();
  return /^(nahi|nahin|na|no|n|galat|wrong)/.test(t);
}
function _yesNoReprompt(langExact='en') {
  const YES_NO = {
    hi: '✅ हाँ या ❌ नहीं — बस इतना बोलो।',
    mr: '✅ हो किंवा ❌ नाही — फक्त एवढं सांगा.',
    gu: '✅ હા અથવા ❌ ના — બસ આ બોલો.',
    bn: '✅ হ্যাঁ অথবা ❌ না — শুধু এটুকু বলুন।',
    ta: '✅ ஆம் அல்லது ❌ இல்லை — இதை மட்டும் சொல்லுங்கள்.',
    te: '✅ అవును లేదా ❌ కాదు — ఇది చెప్పండి.',
    kn: '✅ ಹೌದು ಅಥವಾ ❌ ಇಲ್ಲ — ಇಷ್ಟು ಮಾತ್ರ ಹೇಳಿ.',
    en: '✅ Yes or ❌ No — just reply with one of those.',
  };
  const base = String(langExact ?? 'en').toLowerCase().split(/[-_]/)[0];
  return YES_NO[base] ?? YES_NO.en;
}
async function _composeFirstTxnPreview(shopId, updates, langExact) {
  try {
    const base = String(langExact ?? 'en').toLowerCase().split(/[-_]/)[0];
    const head = base === 'hi' ? '🧾 मैंने समझा:' : '🧾 I understood:';
    const lines = (updates ?? []).slice(0, 6).map(u => {
      const qty = u?.quantity ?? '?';
      const unit = u?.unit ? ` ${u.unit}` : '';
      const prod = u?.product ?? u?.productDisplay ?? '?';
      const act = u?.action ?? '';
      const price = Number.isFinite(u?.pricePerUnit) ? ` @ ₹${u.pricePerUnit}` : '';
      return `• ${act} ${qty}${unit} ${prod}${price}`.trim();
    });
    // Best-effort stock info for first item
    let stockLine = '';
    try {
      const u0 = (updates ?? [])[0];
      const prod0 = u0?.product ?? u0?.productDisplay;
      const unit0 = u0?.unit ?? 'pieces';
      if (prod0 && typeof getProductTotalQuantity === 'function') {
        const r = await getProductTotalQuantity(shopId, prod0, unit0);
        if (r?.success) stockLine = `📦 Stock: ${r.total} ${canonicalizeUnitToken(r.unit ?? unit0)}`;
      }
    } catch { /* noop */ }
    const ask = base === 'hi' ? 'सही है? (Haan/Nahi)' : 'Is this correct? (Yes/No)';
    return [head, ...lines, stockLine, '', ask].filter(Boolean).join('\n');
  } catch {
    return 'Is this correct? (Yes/No)';
  }
}
function markActivationStartInGamify(shopId) {
  try {
    const state = readGamify();
    const gs = state[shopId] || { points: 0, entries: 0, streakDays: 0, lastActivityDate: null, badges: [] };
    if (!gs.activationStartAtMs) gs.activationStartAtMs = Date.now();
    if (typeof gs.first48hCount !== 'number') gs.first48hCount = 0;
    gs.ahaCommitted = true;
    state[shopId] = gs;
    writeGamify(state);
  } catch { /* noop */ }
}
function bump48hTxnCountInGamify(shopId, delta = 1) {
  try {
    const state = readGamify();
    const gs = state[shopId] || { points: 0, entries: 0, streakDays: 0, lastActivityDate: null, badges: [] };
    const start = Number(gs.activationStartAtMs ?? 0);
    if (start > 0 && (Date.now() - start) <= (48 * 60 * 60 * 1000)) {
      gs.first48hCount = Number(gs.first48hCount ?? 0) + Number(delta ?? 1);
      if (gs.first48hCount >= 3 && !(gs.badges ?? []).includes('3-in-48h')) {
        gs.badges = Array.isArray(gs.badges) ? gs.badges : [];
        gs.badges.push('3-in-48h');
        console.log('[activation-metric] reached 3+ real txns in 48h', { shopId, first48hCount: gs.first48hCount });
      }
    }
    state[shopId] = gs;
    writeGamify(state);
  } catch { /* noop */ }
}

function _benefitsForShopType(type, langExact='en') {
  const L = String(langExact ?? 'en').toLowerCase();
  const startLbl = _startTrialLabel(langExact);
  const t = String(type ?? '').toLowerCase();
  const isHi = L.startsWith('hi');
  const isHiLatn = L === 'hi-latn';

  if (t === 'mobile') {
    if (isHiLatn) {
      return `📱 Mobile shop: cover/charger/earphones stock track + low-stock alerts + sales summary.\nTry: purchased Charger 10 pcs @ ₹120\n“${startLbl}” dabao (free ${TRIAL_DAYS} days).`;
    }
    if (isHi) {
      return `📱 मोबाइल शॉप: कवर/चार्जर/ईयरफोन स्टॉक ट्रैक + कम-स्टॉक अलर्ट + बिक्री सारांश।\nTry: purchased Charger 10 pcs @ ₹120\n“${startLbl}” दबाएँ (free ${TRIAL_DAYS} days).`;
    }
    return `📱 Mobile shops: track covers/chargers/earphones stock + low-stock alerts + sales summary.\nTry: purchased Charger 10 pcs @ ₹120\nTap “${startLbl}” (free ${TRIAL_DAYS} days).`;
  }

  // fallback: use generic micro-demo
  const pack = _langPack(langExact);
  return pack.microDemo(TRIAL_DAYS, startLbl);
}

function _renderPreActSalesReply({ shopId, langExact, userText }) {
  const pack = _langPack(langExact);
  const startLbl = _startTrialLabel(langExact);

  const intent = _detectObjectionIntent(userText);
  if (intent) {
    return _withStartFreeTrialLabel(_stripUncertainPhrases([
      pack.objection?.[intent] ?? pack.welcome(TRIAL_DAYS, startLbl, ASK_VIDEO_IN_WELCOME),
      '',
      pack.microDemo(TRIAL_DAYS, startLbl),
      '',
      pack.askShopType
    ].join('\n')), langExact);
  }

  const st = _leadGet(shopId) ?? _leadSet(shopId, { stage: 'S0', lastLang: langExact });
  const type = _detectShopType(userText);
  // If user already mentioned shop type (e.g., “मेरे मोबाइल फ़ोन की दुकान…”, or “मोबाइल”), reply tailored benefits immediately.
    if (type) {
      _leadSet(shopId, { stage: 'S2', shopType: type, lastLang: langExact });
      return _withStartFreeTrialLabel(_stripUncertainPhrases(_benefitsForShopType(type, langExact)), langExact);
    }
  if (st.stage === 'S0') {
    _leadSet(shopId, { stage: 'S1', lastLang: langExact });
    return _withStartFreeTrialLabel(_stripUncertainPhrases([
      pack.welcome(TRIAL_DAYS, startLbl, ASK_VIDEO_IN_WELCOME),
      pack.askShopType
    ].join('\n')), langExact);
  }

  if (st.stage === 'S1') {
    if (type) _leadSet(shopId, { stage: 'S2', shopType: type, lastLang: langExact });
    return _withStartFreeTrialLabel(_stripUncertainPhrases([
      pack.microDemo(TRIAL_DAYS, startLbl),
      '',
      pack.askShopType
    ].join('\n')), langExact);
  }

  // S2+
  return _withStartFreeTrialLabel(_stripUncertainPhrases(pack.microDemo(TRIAL_DAYS, startLbl)), langExact);
}

const { execSync } = require('child_process');
const ffmpegPath = require('@ffmpeg-installer/ffmpeg').path;

const CAPTURE_SHOP_DETAILS_ON = String(process.env.CAPTURE_SHOP_DETAILS_ON ?? 'paid').toLowerCase();
// 'paid' → capture after payment; 'trial' → capture during trial onboarding

// ---------------------------------------------------------------------------
// Ultra‑early ack: micro language hint based on Unicode script and Hinglish ASCII
// ---------------------------------------------------------------------------
function guessLangFromInput(s = '') {
  try {
    const text = String(s || '').trim();
    if (!text) return 'en';
    // Script blocks → native languages
    if (/[\u0900-\u097F]/.test(text)) return 'hi';   // Devanagari → Hindi/Marathi
    if (/[\u0980-\u09FF]/.test(text)) return 'bn';   // Bengali
    if (/[\u0B80-\u0BFF]/.test(text)) return 'ta';   // Tamil
    if (/[\u0C00-\u0C7F]/.test(text)) return 'te';   // Telugu
    if (/[\u0C80-\u0CFF]/.test(text)) return 'kn';   // Kannada
    if (/[\u0A80-\u0AFF]/.test(text)) return 'gu';   // Gujarati
    // ASCII Hinglish detector → Roman Hindi (hi‑latn)    
    const t = text.toLowerCase();
    const isAscii = /^[\x00-\x7F]+$/.test(t);
    // Verbish tokens (existing)
    const hinglishTokens = /\b(kya|kaise|kyon|kyu|kab|kitna|kitni|daam|kimat|fayda|nuksan|bana|sakte|skte|hai|h|kharid|khareed|bech|bikri|dukaan|naam)\b/;
    // NEW: common Roman‑Hindi nouns seen in inventory
    const hinglishNouns = /\b(doodh|dudh|chini|atta|aata|tel|namak|chai|sabzi|sabji|dal|daal|chawal|maggi|amul|parle|parle\-g|frooti|oreo)\b/;      
     // Treat one-word commands as language-neutral (prefer DB or 'en')
     const COMMAND_ONLY = new Set(['mode','help','demo','trial','paid','activate','start']);
     if (COMMAND_ONLY.has(text.toLowerCase())) return 'en';         
     // Widen detection: verbs OR nouns keep us in Roman-Hindi
     if (isAscii && (hinglishTokens.test(t) || hinglishNouns.test(t))) return 'hi-latn';
    return 'en';
  } catch {
    return 'en';
  }
}

// ---------------------------------------------------------------------------
// [PATCH:LANG-FIX-INTERACTIVE-ALL-20260223] Infer UI language from interactive tap text
// Uses Unicode script ranges + Marathi-vs-Hindi disambiguation for Devanagari.
// Supports: hi, mr, bn, ta, te, kn, gu (and falls back to null for Latin).
// ---------------------------------------------------------------------------
function inferLangFromTapText(t = '') {
  const s = String(t ?? '').trim();
  if (!s) return null;
  // Devanagari (Hindi/Marathi). Disambiguate using Marathi tokens from your own labels.
  if (/[\u0900-\u097F]/.test(s)) {        
    // Expand Marathi cues beyond just "खरेदी/नोंदवा" to avoid defaulting Marathi taps to Hindi.
    // Examples observed in flows: "नवीन प्रॉडक्ट", "निवडा", etc.
      if (/(खरेदी|नोंदवा|नवीन|प्रॉडक्ट|निवडा|जुने|सराव|डेमो|साठा|पुढील|कृती)/.test(s)) return 'mr';
    return 'hi';
  }
  if (/[\u0980-\u09FF]/.test(s)) return 'bn';
  if (/[\u0B80-\u0BFF]/.test(s)) return 'ta';
  if (/[\u0C00-\u0C7F]/.test(s)) return 'te';
  if (/[\u0C80-\u0CFF]/.test(s)) return 'kn';
  if (/[\u0A80-\u0AFF]/.test(s)) return 'gu';
  return null;
}

// ========================================================================
// [UNIQ:VOICE-CONF-005] Voice (STT) confidence minimum — environment-driven
// Default to 0.60 for audio turns; upstream handlers can read this constant.
// ========================================================================
const STT_CONFIDENCE_MIN_VOICE = Number(process.env.STT_CONFIDENCE_MIN_VOICE ?? 0.60);

// ============================================================================
// Soniox language hints adapter
// Maps your detected/pinned language into the single-language hint Soniox expects
// (recommended to maximize accuracy when you know the language). [2](https://soniox.com/docs/stt/concepts/language-restrictions)
// Supported languages list: hi, bn, ta, te, kn, mr, gu, en. [3](https://soniox.com/docs/stt/concepts/supported-languages)
// ============================================================================
function mapLangToSonioxHints(langCode) {
  const L = String(langCode ?? 'en').toLowerCase();
  switch (L) {
    case 'hi':
    case 'bn':
    case 'ta':
    case 'te':
    case 'kn':
    case 'mr':
    case 'gu':
    case 'en':
      return [L];
    // Romanized variants → prefer English transcription in Latin script
    case 'hi-latn':
    case 'bn-latn':
    case 'ta-latn':
    case 'te-latn':
    case 'kn-latn':
    case 'mr-latn':
    case 'gu-latn':
      return ['en'];
    default:
      return ['en'];
  }
}

function getShopId(from) {
  const prefix = 'whatsapp:';
  return (typeof from === 'string' && from.startsWith(prefix)) ? from.slice(prefix.length) : from;
}

function queueUpsellIfNeeded(gateObj) {
  // Avoid ReferenceError if 'gate' is not defined in scope
  try {
    if (gateObj && gateObj.upsellReason) {
      return scheduleUpsell(gateObj.upsellReason);
    }
  } catch { /* swallow */ }
  return Promise.resolve();
}

/**
 * Resolve Soniox language hints for a given WhatsApp 'From'.
 * Priority:
 *  1) User preference (pinned), if available
 *  2) Detected language from this turn (hint)
 *  3) Fallback 'en'
 */
async function resolveSonioxLanguageHints(From, detectedLanguageHint = 'en') {
  let lang = String(detectedLanguageHint ?? 'en').toLowerCase();
  try {
    const shopId = String(From ?? '').replace('whatsapp:', '');
    if (typeof getUserPreference === 'function') {
      const pref = await getUserPreference(shopId).catch(() => null);
      if (pref?.success && pref.language) lang = String(pref.language).toLowerCase();
    }
  } catch { /* noop */ }
  return mapLangToSonioxHints(lang);
}

/**
 * Detect whether a message body contains a transaction confirmation.
 * - opts.strict === true → match only canonical confirmation lines (success paths).
 * - default (non-strict) → fall back to a broader heuristic.
 *
 * Canonical heads:
 *  🛒 sale, 📦 purchase, ↩️ return, ✅ verbose EN sale header (only in EN header form).
 *
 * Notes:
 *  - Checks the FIRST line only (confirmation line), ignoring the later "✅ 1 में से 1 आइटम…" & footers.
 *  - Supports Hindi price forms: "@ ₹65" and "₹60/लीटर पर".
 *  - Stock words include localized forms: "Stock/स्टॉक/স্টক/ஸ்டாக்/స్టాక్/ಸ್ಟಾಕ್/સ્ટોક".
 */
function looksLikeTxnConfirmation(text, opts = {}) {
  const s0 = String(text ?? '').trim();
  if (!s0) return false;

  // Only inspect the first line (actual confirmation)
  const firstLine = s0.split(/\r?\n/)[0].trim();

  // NEW: detect "Undone" confirmations (localized) and suppress Undo CTA
  // Allows an optional ↩️ at the start, then language-specific token, then ":".
  // Tokens include: EN "Undone"/"Undo"; hi "रद्द"/"पूर्ववत"/"वापस लिया"; gu "રદ"/"બાતિલ"/"પૂર્વવત";
  // ta "ரத்து"/"மீளமை(ப்பு)"; te "రద్దు"; kn "ರದ್ದು"; mr "रद्द"/"पूर्ववत"; bn "বাতিল"/"পূর্বাবস্থায় ফেরত"; pa "ਰੱਦ"/"ਪਿਛੇ ਲਿਆ".
  const HEAD_UNDONE_ANY = new RegExp(
    String.raw`^(?:\u21A9\uFE0F\s*)?(?:` +
      // EN
      `Undone|Undo(?:ne)?|` +
      // hi
      `रद्द(?:\\s*किया)?|पूर्ववत|वापस\\s*लिया|` +
      // gu
      `રદ|બાતિલ|પૂર્વવત|` +
      // ta
      `ரத்து|மீளமை(?:ப்பு)?|` +
      // te
      `రద్దు|` +
      // kn
      `ರದ್ದು|` +
      // mr
      `रद्द|पूर्ववत|` +
      // bn
      `বাতিল|পূর্বাবস্থায়(?:\\s*ফেরত)?|` +
      // pa
      `ਰੱਦ|ਪਿਛੇ\\s*ਲਿਆ` +
    `)\\s*:`,
    'iu'
  );

  if (HEAD_UNDONE_ANY.test(firstLine)) {
    return false;               // treat as final ack; no Undo button
  }

  // Normalize numerals for digit checks
  let lineLatin = firstLine;
  try { lineLatin = normalizeNumeralsToLatin(firstLine); } catch {}

  const hasDigit = /\d/.test(lineLatin);

  // Heads
  const HEAD_SALE     = /^🛒\s*/u;    // 🛒
  const HEAD_PURCHASE = /^📦\s*/u;    // 📦
  const HEAD_RETURN   = /^\u21A9\uFE0F\s*/u; // ↩️
  const HEAD_VERBOSE  = /^\u2705\s*/u;       // ✅ (EN verbose header only)

  // Price markers:
  const PRICE_AT_RX   = /@\s*(?:₹|Rs\.?|INR)\s*\d+(?:\.\d+)?(?:\/[^\s)]+)?/iu;
  const PRICE_PER_HI  = /(?:₹|Rs\.?|INR)\s*\d+(?:\.\d+)?(?:\/[^\s)]+)?\s*पर\b/iu;
  const PRICE_ANY_RX  = /(?:₹|Rs\.?|INR)\s*\d+(?:\.\d+)?/iu;

  const hasPrice = PRICE_AT_RX.test(firstLine) || PRICE_PER_HI.test(firstLine) || PRICE_ANY_RX.test(firstLine);

  // Localized "stock" words
  const STOCK_WORDS = ['Stock','स्टॉक','স্টক','ஸ்டாக்','స్టాక్','ಸ್ಟಾಕ್','સ્ટોક'];
  const STOCK_RX = new RegExp(
    String.raw`\(\s*(?:${STOCK_WORDS.map(w => w.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')).join('|')})\s*:\s*\d+(?:\.\d+)?\s+[^\)]+\)`,
    'u'
  );
  const hasStock = STOCK_RX.test(firstLine);

  // Hindi verb variants (morphology)
  const HI_PURCHASE_VERB = /(खरीद(?:[ाी]|ी)?\s*ग(?:या|ई|ए|ईं)?|खरीदा|खरीदी)/u;
  const HI_RETURN_VERB   = /(वापस\s*की\s*ग(?:ई|ए|या|ईं)?|वापसी)/u;
  const HI_SALE_VERB     = /(बेच(?:[ाी])?\s*ग(?:या|ई|ए|ईं)?|बेचा|बेची|बिक्री)/u;

  // EN verbose sale header (your composer): "✅ product — sold {qty} {unit} @ ₹{price}"
  const EN_VERBOSE_SALE  = /^\u2705\s*.+?\s+—\s+sold\s+\d+(?:\.\d+)?\s+[^\s]+(?:\s+@\s+(?:₹|Rs\.?|INR)\s*\d+(?:\.\d+)?)?$/iu;

  if (opts.strict === true) {
    if (HEAD_PURCHASE.test(firstLine)) {
      return hasDigit && (hasPrice || hasStock || HI_PURCHASE_VERB.test(firstLine));
    }
    if (HEAD_RETURN.test(firstLine)) {
      return hasDigit && (hasPrice || hasStock || HI_RETURN_VERB.test(firstLine));
    }
    if (HEAD_SALE.test(firstLine)) {
      return hasDigit && (hasPrice || hasStock || HI_SALE_VERB.test(firstLine));
    }
    if (HEAD_VERBOSE.test(firstLine)) {
      return EN_VERBOSE_SALE.test(firstLine);
    }
    return false;
  }

  // --- Non-strict fallback: emoji/bullets + qty + "unit-ish" token ---
  try {
    const unitRx =
      (typeof UNIT_REGEX === 'object' && UNIT_REGEX) ||
      /\b(kg|kgs|g|gm|gms|l|ltr|ltrs|ml|packet|packets|piece|pieces|लीटर|पैकेट|बोतल(?:ें)?|नंग|लिटर|पॅकेट|લિટર|પેકેટ|બોટલ(?:ો)?|லிட்டர்|பாக்கெட்|లీటర్|ప్యాకెట్|ಲೀಟರ್|ಪ್ಯಾಕೆಟ್)\b/iu;

    const hasHead = HEAD_SALE.test(firstLine) || HEAD_PURCHASE.test(firstLine) || HEAD_RETURN.test(firstLine) || /^[•]/.test(firstLine);
    const hasUnit = unitRx.test(firstLine);

    return hasHead && hasDigit && hasUnit;
  } catch {
    return (HEAD_SALE.test(firstLine) || HEAD_PURCHASE.test(firstLine) || HEAD_RETURN.test(firstLine) || HEAD_VERBOSE.test(firstLine)) && hasDigit;
  }
}


