    const PREMIUM_TE = `₹${price}/month ONLY: Full Summary + Daily AI Summary + 8 AM price reminders.`;
    const FREE_TE    = `🆓 Basic inventory (stock add/update + inventory queries) trial తర్వాత కూడా FREE.`;
  
